def build_toc(markdown):
    counts = {}
    toc_lines = []
    for line in markdown.splitlines():
        if line.startswith("## "):
            level = 2
            text = line[3:].strip()
        elif line.startswith("### "):
            level = 3
            text = line[4:].strip()
        else:
            continue

        base = "".join(c for c in text.lower() if c.isalnum() or c == " ").replace(" ", "-")
        count = counts.get(base, 0)
        if count:
            anchor = f"{base}-{count}"
        else:
            anchor = base
        counts[base] = count + 1

        indent = "  " if level == 3 else ""
        toc_lines.append(f"{indent}- [{text}](#{anchor})")

    return "\n".join(toc_lines)
